// Router: detecta se é fluxo deferred (job_id + callback_url) e repassa o body.
const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const hasDefer = !!(body.job_id && body.callback_url);
return [{ json: { ...body, _defer: hasDefer, _job_id: body.job_id || null } }];

// Montar prompt e modelo (branch async). Entrada = mesmo item do Router (body + _defer, _job_id).
const body = $input.first().json;
const promptFromBody = body.prompt || (body.metadata && body.metadata.prompt) || '';
const systemPrompt = (promptFromBody && String(promptFromBody).trim()) ? String(promptFromBody).trim() : 'Você é um assistente prestativo.';
const knowledgeItems = Array.isArray(body.knowledge_items) ? body.knowledge_items : [];
const context = knowledgeItems.map(i => `## ${i.title || 'Documento'}\n${i.content || ''}`).join('\n\n');
const model = (body.metadata && body.metadata.model) ? String(body.metadata.model).trim() : (body.model ? String(body.model).trim() : 'llama3.2');
const knowledgeItemsCount = knowledgeItems.length;
const useChat = Array.isArray(body.messages) && body.messages.length > 0;

if (useChat) {
  const systemContent = [systemPrompt, context ? 'Contexto para consulta:\n' + context : ''].filter(Boolean).join('\n\n');
  const messages = [
    { role: 'system', content: systemContent },
    ...body.messages.map(m => ({ role: (m.role || 'user').toLowerCase(), content: String(m.content || '') }))
  ];
  return [{ json: { useChat: true, model, messages, knowledgeItemsCount, callback_url: body.callback_url, job_id: body.job_id, request_id: body.request_id, trace_id: body.trace_id } }];
}

const userMessage = (body.message && body.message.content) ? String(body.message.content) : '';
const fullPrompt = [
  systemPrompt,
  context ? 'Contexto para consulta:\n' + context : '',
  userMessage ? 'Mensagem do usuário: ' + userMessage : ''
].filter(Boolean).join('\n\n');

return [{ json: { useChat: false, model, fullPrompt, knowledgeItemsCount, callback_url: body.callback_url, job_id: body.job_id, request_id: body.request_id, trace_id: body.trace_id } }];

// Formatar resposta da IA e anexar dados do callback (job_id, callback_url, request_id, trace_id).
const ollama = $input.first().json;
const prev = $('Montar prompt (async)').first().json;
const replyText = (ollama.message && ollama.message.content)
  ? String(ollama.message.content).trim()
  : (ollama.response && String(ollama.response).trim())
    ? String(ollama.response).trim()
    : '(Sem resposta do modelo.)';
const latencyMs = ollama.eval_duration ? Math.round(ollama.eval_duration * 1000) : 0;

return [{
  json: {
    reply_text: replyText,
    status: 'success',
    meta: {
      model: ollama.model || prev.model,
      latency_ms: latencyMs,
      rag_hits: prev.knowledgeItemsCount || 0
    },
    callback_url: prev.callback_url,
    job_id: prev.job_id,
    request_id: prev.request_id,
    trace_id: prev.trace_id
  }
}];

// Montar body do callback para o Sense.
const d = $input.first().json;
return [{
  json: {
    job_id: d.job_id,
    status: 'success',
    request_id: d.request_id || null,
    trace_id: d.trace_id || null,
    response: {
      reply_text: d.reply_text,
      meta: d.meta || {}
    }
  }
}];

